rack_height = 1500;
rack_width = 650;
rack_length = 850;
bar_thickness = 30;
wheel_radius = 50;
wheel_width = 30;

module wheel() {
    color("blue")
    rotate([90, 0, 0])
    cylinder(r=wheel_radius, h=wheel_width, center=true);
}

module frame() {
    color("silver") {
        // Vertical posts
        translate([0, 0, rack_height/2]) {
            translate([rack_width/2, rack_length/2, 0]) cube([bar_thickness, bar_thickness, rack_height], center=true);
            translate([-rack_width/2, rack_length/2, 0]) cube([bar_thickness, bar_thickness, rack_height], center=true);
            translate([rack_width/2, -rack_length/2, 0]) cube([bar_thickness, bar_thickness, rack_height], center=true);
            translate([-rack_width/2, -rack_length/2, 0]) cube([bar_thickness, bar_thickness, rack_height], center=true);
        }

        // Horizontal bars
        for (h = [300, 600, 900, 1200]) {
            translate([0, 0, h]) {
                cube([rack_width, bar_thickness, bar_thickness], center=true);
                cube([bar_thickness, rack_length, bar_thickness], center=true);
            }
        }

        // Base frame
        translate([0, 0, bar_thickness/2]) {
            cube([rack_width, bar_thickness, bar_thickness], center=true);
            cube([bar_thickness, rack_length, bar_thickness], center=true);
        }
    }
}

union() {
    frame();

    // Wheels
    translate([rack_width/2, rack_length/2, 0]) wheel();
    translate([-rack_width/2, rack_length/2, 0]) wheel();
    translate([rack_width/2, -rack_length/2, 0]) wheel();
    translate([-rack_width/2, -rack_length/2, 0]) wheel();
}

