module gear_profile() {
    union() {
        cylinder(r = gear_radius, h = gear_thickness_base, $fn = 100);
        cylinder(r1 = gear_radius, r2 = gear_radius - 5, h = gear_thickness_base + gear_thickness_top, $fn = 100);
    }
}

module tooth() {
    translate([gear_radius - 2, 0, 0])
    cube([tooth_depth * 2, 10, gear_thickness_base + gear_thickness_top], center = true);
}

difference() {
    union() {
        gear_profile();
        for (i = [0 : teeth_count - 1]) {
            rotate([0, 0, i * (360 / teeth_count)])
            tooth();
        }
    }

    cube([hole_size, hole_size, (gear_thickness_base + gear_thickness_top) * 2], center = true);
}

