    cylinder(r=rod_radius, h=rod_height, $fn=50);

    // Flange at base of rod
    translate([0, 0, 0])
    cylinder(r=flange_radius, h=flange_thickness, $fn=50);

    // Bent Pipe Base
    translate([0, 0, -pipe_radius])
    rotate([0, 90, 0])
    union() {
        cylinder(r=pipe_radius, h=50, $fn=50);
        rotate_extrude(angle=90, $fn=50)
        translate([50, 0, 0])
        circle(r=pipe_radius, $fn=50);
        translate([50, 50, 0])
        rotate([90, 0, 0])
        cylinder(r=pipe_radius, h=50, $fn=50);
    }

    // Flange at end of pipe
    translate([100, 50, -pipe_radius])
    rotate([90, 0, 0])
    cylinder(r=flange_radius, h=flange_thickness, $fn=50);

    // Gear Mechanism
    translate([rod_radius + 5, 0, rod_height / 2])
    rotate([0, 90, 0])
    difference() {
        union() {
            cylinder(r=gear_radius, h=gear_thickness, $fn=20);
            for (i = [0:12]) {
                rotate([0, 0, i * 30])
                translate([gear_radius - 2, 0, 0])
                cube([10, 4, gear_thickness], center=true);
            }
        }
        cylinder(r=5, h=gear_thickness + 2, center=true, $fn=20);
    }
}

