// 3. Hollow Pyramid with Cross Support
module hollow_pyramid() {
    difference() {
        // Outer pyramid
        cylinder(r1 = base_size, r2 = 0, h = height, $fn = 4);
        // Inner hollow
        translate([0, 0, 2])
        scale([0.8, 0.8, 0.9])
        cylinder(r1 = base_size, r2 = 0, h = height, $fn = 4);

        // Cutouts to show interior
        translate([0, 0, height/2]) cube([base_size*2, 2, height], center=true);
        translate([0, 0, height/2]) cube([2, base_size*2, height], center=true);
    }
    // Cross support
    intersection() {
        union() {
            cube([base_size * 1.2, 2, height], center = true);
            cube([2, base_size * 1.2, height], center = true);
        }
        cylinder(r1 = base_size * 0.8, r2 = 0, h = height * 0.9, $fn = 4);
    }
}

