module wireframe_box(l, w, h, t) {
    // Edges
    for (x = [0, l]) for (y = [0, w]) translate([x, y, 0]) rotate([0, 0, 0]) cylinder(h=h, r=t/2, $fn=16);
    for (x = [0, l]) for (z = [0, h]) translate([x, 0, z]) rotate([0, 90, 0]) cylinder(h=w, r=t/2, $fn=16);
