module twisting_cylinder(h, r, twist) {
    for (i = [0:twist_steps]) {
        translate([0, 0, i * (h / twist_steps)])
        rotate([0, 0, i * (twist / twist_steps)])
        cylinder(h = h / twist_steps, r = r - (i * 0.5), $fn = 20);
    }
}

module lattice_sphere() {
    difference() {
        sphere(r = sphere_radius);
        for (i = [0:10]) {
            rotate([i * 20, i * 15, 0])
            cube([sphere_radius * 2, lattice_thickness, lattice_thickness], center = true);
            rotate([0, i * 20, i * 15])
            cube([lattice_thickness, sphere_radius * 2, lattice_thickness], center = true);
        }
    }
}

