module notched_cube() {
    difference() {
        cube(cube_size, center = true);
        for (i = [-1, 1]) {
            translate([i * (cube_size / 2), 0, 0]) rotate([0, 90, 0]) cylinder(r = notch_depth / 2, h = 2, center = true);
            translate([0, i * (cube_size / 2), 0]) rotate([90, 0, 0]) cylinder(r = notch_depth / 2, h = 2, center = true);
            translate([0, 0, i * (cube_size / 2)]) cylinder(r = notch_depth / 2, h = 2, center = true);
        }
    }
}

module tiered_cone() {
    union() {
        for (i = [0:4]) {
            translate([0, 0, i * (cone_height / 5)])
            cylinder(r = cone_radius * (1 - i / 5), h = cone_height / 5, $fn = 32);
        }
    }
}

module gear_sphere() {
    union() {
        sphere(r = sphere_radius, $fn = 32);
        for (i = [0:gear_teeth]) {
            rotate([0, (i / gear_teeth) * 360, 0])
            rotate([0, 90, 0])
            translate([0, 0, sphere_radius])
            cylinder(r = 2, h = 5, $fn = 8);
        }
    }
}

