module gear(r, thickness, teeth) {
    union() {
        cylinder(r = r, h = thickness, $fn = 64);
        for (i = [0 : teeth - 1]) {
            rotate([0, 0, i * (360 / teeth)])
            translate([r, 0, 0])
            cube([tooth_depth * 2, 5, thickness], center = true);
        }
    }
}

module pipe_segment(length) {
    difference() {
        cylinder(r = pipe_outer_radius, h = length, $fn = 64);
        cylinder(r = pipe_inner_radius, h = length, $fn = 64);
    }
}

union() {
    // Elbow joint
    difference() {
        rotate_extrude(angle = 90, $fn = 64)
        translate([pipe_length, 0, 0])
        circle(r = pipe_outer_radius, $fn = 64);

        rotate_extrude(angle = 90, $fn = 64)
        translate([pipe_length, 0, 0])
        circle(r = pipe_inner_radius, $fn = 64);
    }

    // End 1
    translate([pipe_length, 0, 0])
    rotate([90, 0, 0])
    gear(gear_radius, gear_thickness, gear_teeth);

    // End 2
    translate([0, pipe_length, 0])
    rotate([0, 90, 0])
    gear(gear_radius, gear_thickness, gear_teeth);
}

