module base_texture() {
    for (i = [0:20:360]) {
        rotate([0, 0, i])
        translate([container_radius * 0.7, 0, 0])
        sphere(r = 3);
    }
}

module container_body() {
    difference() {
        union() {
            cylinder(r = container_radius, h = container_height);
            base_texture();
        }
        translate([0, 0, wall_thickness])
        cylinder(r = container_radius - wall_thickness, h = container_height);

        rotate([0, 0, 45])
        translate([0, 0, 10])
        rotate_extrude(angle = cutout_angle)
        translate([container_radius - wall_thickness, 0, 0])
        square([wall_thickness * 2, container_height - 30]);
    }
}

module cap() {
    translate([0, 0, container_height])
    union() {
        cylinder(r = container_radius + 2, h = cap_height);
        translate([0, 0, -5])
        cylinder(r = container_radius - 0.5, h = 5);
    }
}

module threads() {
    intersection() {
        for (i = [0:thread_pitch:container_height - 60]) {
            translate([0, 0, i + 60])
            rotate_extrude()
            translate([container_radius - 1, 0, 0])
            circle(r = 1);
        }
        cylinder(r = container_radius + 2, h = container_height);
    }
}

union() {
    container_body();
    threads();
    cap();
}

