cube_size = 50;
frame_thickness = 8;
peg_radius = 2;
peg_height = 4;
pegs_per_edge = 4;

module hollow_cube_frame() {
    difference() {
        cube([cube_size, cube_size, cube_size], center = true);
        cube([cube_size - (2 * frame_thickness), cube_size - (2 * frame_thickness), cube_size + 1], center = true);
        cube([cube_size - (2 * frame_thickness), cube_size + 1, cube_size - (2 * frame_thickness)], center = true);
        cube([cube_size + 1, cube_size - (2 * frame_thickness), cube_size - (2 * frame_thickness)], center = true);
    }
}

module peg() {
    cylinder(r = peg_radius, h = peg_height, $fn = 20);
}

module edge_pegs(length, count) {
    spacing = length / (count + 1);
    for (i = [1 : count]) {
        translate([-(length / 2) + (i * spacing), 0, 0])
            rotate([90, 0, 0])
                peg();
    }
}

union() {
    hollow_cube_frame();

    // Edges along X axis
    for (y = [-1, 1]) {
        for (z = [-1, 1]) {
            translate([0, y * (cube_size / 2 - frame_thickness / 2), z * (cube_size / 2 - frame_thickness / 2)])
                rotate([0, 0, 0])
                    edge_pegs(cube_size - 2 * frame_thickness, pegs_per_edge);
        }
    }

    // Edges along Y axis
    for (x = [-1, 1]) {
        for (z = [-1, 1]) {
            translate([x * (cube_size / 2 - frame_thickness / 2), 0, z * (cube_size / 2 - frame_thickness / 2)])
                rotate([0, 0, 90])
                    edge_pegs(cube_size - 2 * frame_thickness, pegs_per_edge);
        }
    }

    // Edges along Z axis
    for (x = [-1, 1]) {
        for (y = [-1, 1]) {
            translate([x * (cube_size / 2 - frame_thickness / 2), y * (cube_size / 2 - frame_thickness / 2), 0])
                rotate([90, 0, 0])
                    edge_pegs(cube_size - 2 * frame_thickness, pegs_per_edge);
        }
    }
}

