segment_height = length / num_segments;

module rainstick() {
    union() {
        // Main body segments
        for (i = [0 : num_segments - 1]) {
            translate([0, 0, i * segment_height])
            difference() {
                cylinder(r = radius, h = segment_height - 0.5, $fn = 64);
                translate([0, 0, -0.1])
                cylinder(r = radius - wall_thickness, h = segment_height + 0.2, $fn = 64);
            }
        }

        // Helical pins
        for (i = [0 : num_segments * pins_per_segment - 1]) {
            angle = i * (360 / pins_per_segment) + (i * 10);
            z_pos = (i / pins_per_segment) * segment_height + (segment_height / 2);

            if (z_pos < length) {
                rotate([0, 0, angle])
                translate([radius - wall_thickness + 0.1, 0, z_pos])
                rotate([0, 90, 0])
                cylinder(r = pin_radius, h = pin_length, $fn = 16);
            }
        }

        // Caps
        cylinder(r = radius, h = 2, $fn = 64);
        translate([0, 0, length - 2])
        cylinder(r = radius, h = 2, $fn = 64);
    }
}

