module chain_link(h) {
    rotate_extrude(angle = 360) translate([5, 0, 0]) circle(r = 1);
}

union() {
    // Central Rod
    cylinder(r = central_rod_radius, h = central_rod_height);

    // Top Hub
    cylinder(r = 20, h = 5);

    // Arms and Shades
    for (i = [0 : num_shades - 1]) {
        angle = i * (360 / num_shades);
        rotate([0, 0, angle]) {
            translate([central_rod_radius, 0, central_rod_height - 10]) {
                rotate([0, 90, 0]) cylinder(r = 2, h = circle_radius);
                translate([circle_radius, 0, 0]) lamp_shade();

                // Hanging ring
                translate([circle_radius, 0, -shade_height]) {
                    rotate([90, 0, 0]) torus(15, 1);
                    // Chain
                    for (j = [0:3]) {
                        translate([0, 0, -j * 5]) rotate([90, 0, 0]) torus(2, 0.5);
                    }
                }
            }
        }
    }

    // Decorative bottom ring
    translate([0, 0, 0]) rotate_extrude() translate([ring_radius, 0, 0]) circle(r = 3);
}

module torus(r_major, r_minor) {
    rotate_extrude() translate([r_major, 0, 0]) circle(r = r_minor);
}

