module frame() {
    union() {
        // Vertical columns
        translate([0, 0, 0]) cube([beam_thickness, beam_thickness, height]);
        translate([length - beam_thickness, 0, 0]) cube([beam_thickness, beam_thickness, height]);
        translate([0, width - beam_thickness, 0]) cube([beam_thickness, beam_thickness, height]);
        translate([length - beam_thickness, width - beam_thickness, 0]) cube([beam_thickness, beam_thickness, height]);

        // Bottom horizontal beams
        translate([0, 0, 0]) cube([length, beam_thickness, beam_thickness]);
        translate([0, width - beam_thickness, 0]) cube([length, beam_thickness, beam_thickness]);
        translate([0, 0, 0]) cube([beam_thickness, width, beam_thickness]);
        translate([length - beam_thickness, 0, 0]) cube([beam_thickness, width, beam_thickness]);

        // Top horizontal beams
        translate([0, 0, height - beam_thickness]) cube([length, beam_thickness, beam_thickness]);
        translate([0, width - beam_thickness, height - beam_thickness]) cube([length, beam_thickness, beam_thickness]);
        translate([0, 0, height - beam_thickness]) cube([beam_thickness, width, beam_thickness]);
        translate([length - beam_thickness, 0, height - beam_thickness]) cube([beam_thickness, width, beam_thickness]);

        // Internal cross supports
        translate([length/2 - beam_thickness/2, 0, 0]) cube([beam_thickness, width, beam_thickness]);
        translate([length/2 - beam_thickness/2, 0, height - beam_thickness]) cube([beam_thickness, width, beam_thickness]);
