module gear_profile(r_outer, r_inner, teeth) {
    union() {
        cylinder(r=r_inner, h=height, $fn=64);
        for (i = [0:teeth-1]) {
            rotate([0, 0, i * (360 / teeth)])
            translate([r_inner - 1, -2, 0])
            cube([r_outer - r_inner + 2, 4, height]);
        }
    }
}

difference() {
    union() {
        // Outer gear structure
        gear_profile(outer_radius, outer_radius - 5, gear_teeth);

        // Irregular segmented surface
        for (i = [0:segments-1]) {
            rotate([0, 0, i * (360 / segments)])
            translate([outer_radius - 2, -5, 0])
            cube([5, 10, height / segments * (i % 3 + 1)]);
        }
    }

