module pyramid_shape() {
    hull() {
        sphere(r = 1, $fn = 4);
        translate([0, 0, pyramid_size])
        cube([0.1, 0.1, 0.1], center = true);
    }
}

difference() {
    union() {
        difference() {
            sphere(r = sphere_radius, $fn = 64);
            sphere(r = sphere_radius - sphere_thickness, $fn = 64);
        }

        for (i = [0 : num_segments]) {
            for (j = [0 : num_segments]) {
                rotate([0, i * (180 / num_segments), j * (360 / num_segments)])
                translate([0, 0, sphere_radius - 1])
                pyramid_shape();
            }
        }
    }

    for (i = [0 : num_segments]) {
        for (j = [0 : num_segments]) {
            rotate([0, i * (180 / num_segments), j * (360 / num_segments)])
            translate([0, 0, sphere_radius - sphere_thickness / 2])
            triangular_cutout();
        }
    }
}

