    union() {
        // Straight section 1
        pipe_segment(pipe_outer_radius, pipe_inner_radius, segment_length);

        // Bend section
        translate([0, 0, segment_length]) {
            rotate_extrude(angle = bend_angle, convexity = 10) {
                translate([bend_radius, 0, 0]) {
                    difference() {
                        circle(r = pipe_outer_radius);
                        circle(r = pipe_inner_radius);
                    }
                }
            }
        }

        // Straight section 2
        translate([0, 0, segment_length]) {
            rotate([0, bend_angle, 0]) {
                translate([bend_radius * sin(bend_angle), 0, bend_radius * (1 - cos(bend_angle))]) {
                    rotate([0, -bend_angle, 0]) {
                        pipe_segment(pipe_outer_radius, pipe_inner_radius, segment_length);
                    }
                }
            }
        }
    }
}

