$fn = 64;

num_rings = 20;
base_radius = 30;
top_radius = 5;
height = 60;
thickness = 4;
spiral_factor = 90;

module ring(radius, height_pos, rotation) {
    rotate([0, 0, rotation])
    translate([0, 0, height_pos])
    rotate_extrude(angle = 360)
    translate([radius, 0, 0])
    circle(r = thickness);
}

union() {
    for (i = [0 : num_rings]) {
        t = i / num_rings;
        current_radius = base_radius * (1 - t) + top_radius * t;
        current_height = height * t;
        current_rotation = spiral_factor * t;

        ring(current_radius, current_height, current_rotation);
    }

    for (i = [0 : num_rings - 1]) {
        t1 = i / num_rings;
        t2 = (i + 1) / num_rings;

        r1 = base_radius * (1 - t1) + top_radius * t1;
        r2 = base_radius * (1 - t2) + top_radius * t2;

        h1 = height * t1;
        h2 = height * t2;

        rot1 = spiral_factor * t1;
        rot2 = spiral_factor * t2;

        hull() {
            rotate([0, 0, rot1]) translate([r1, 0, h1]) sphere(r = thickness);
            rotate([0, 0, rot2]) translate([r2, 0, h2]) sphere(r = thickness);
        }
    }
}

