cone_radius = 8;
cone_height = 15;

module humanoid() {
    union() {
        // Torso
        cylinder(r=4, h=body_height, center=true);

        // Ribs
        for (i = [0 : rib_count - 1]) {
            z_pos = -body_height/3 + (i * (body_height/1.5 / rib_count));
            rotate([0, 90, 0])
            cylinder(r=0.5, h=10, center=true);
            translate([0, 0, z_pos])
            rotate([0, 90, 0])
            cylinder(r=0.5, h=10, center=true);
        }

        // Arms
        translate([6, 0, body_height/3])
        rotate([0, 30, 0])
        cylinder(r=limb_thickness/2, h=40);
        translate([-6, 0, body_height/3])
        rotate([0, -30, 0])
        cylinder(r=limb_thickness/2, h=40);

        // Legs
        translate([2, 0, -body_height/2])
        rotate([0, -10, 0])
        cylinder(r=limb_thickness/2, h=40);
        translate([-2, 0, -body_height/2])
        rotate([0, 10, 0])
        cylinder(r=limb_thickness/2, h=40);

        // Head
        translate([0, 0, body_height/2 + 5]) {
            sphere(r=head_radius);

            // Rod
            rotate([90, 0, 0])
            cylinder(r=1, h=20, center=true);

            // Cones
            translate([0, 10, 0])
            rotate([90, 0, 0])
            cylinder(r1=cone_radius, r2=0, h=cone_height);

            translate([0, -10, 0])
            rotate([-90, 0, 0])
            cylinder(r1=cone_radius, r2=0, h=cone_height);
        }
    }
}

