    difference() {
        cube([case_width, case_depth, case_height], center=true);
        translate([0, 0, wall_thickness])
            cube([case_width - 2*wall_thickness, case_depth - 2*wall_thickness, case_height], center=true);
    }
    // Clasps
    for(a = [0, 180]) {
        rotate([0, 0, a])
        translate([case_width/2, 0, 0])
            cube([2, 10, 5], center=true);
    }
