translate([0, 0, 0]) {
    difference() {
        cylinder(r1=funnel_top_r, r2=funnel_bottom_r, h=funnel_height);
        translate([0, 0, 2])
            cylinder(r1=funnel_top_r-wall_thickness, r2=funnel_bottom_r-1, h=funnel_height);
    }
}

// Spherical Cap with Ridges
translate([70, 0, 0]) {
    intersection() {
        sphere(r=sphere_r, $fn=50);
        translate([0, 0, -sphere_r/2])
            cube([sphere_r*2, sphere_r*2, sphere_r], center=true);
    }
    for(i = [1:ridge_count]) {
        translate([0, 0, i * (sphere_r/ridge_count) - 5])
            rotate_extrude($fn=50)
                translate([sqrt(pow(sphere_r, 2) - pow(i*(sphere_r/ridge_count)-5, 2)) - 0.5, 0, 0])
                    circle(r=0.5, $fn=20);
    }
}

