module panel(w, h) {
    difference() {
        cube([w, h, thickness]);
        translate([5, 5, 0]) cylinder(r=2, h=thickness, $fn=20);
        translate([w-5, 5, 0]) cylinder(r=2, h=thickness, $fn=20);
        translate([5, h-5, 0]) cylinder(r=2, h=thickness, $fn=20);
        translate([w-5, h-5, 0]) cylinder(r=2, h=thickness, $fn=20);
    }
