    panel(box_depth, box_height);
    translate([0, box_height, 0]) flap(box_depth);
}

// Right
translate([box_width + thickness, 0, 0]) rotate([0, -90, 0]) {
    panel(box_depth, box_height);
    translate([0, box_height, 0]) flap(box_depth);
}

