module rod(p1, p2, color_val) {
    vector = p2 - p1;
    distance = norm(vector);
    angle_z = atan2(vector[1], vector[0]);
    angle_y = atan2(sqrt(pow(vector[0], 2) + pow(vector[1], 2)), vector[2]);

    color(color_val)
    translate(p1)
    rotate([0, angle_y, angle_z])
    cylinder(r = rod_radius, h = distance);
}

module edge_frame(p1, p2) {
    vector = p2 - p1;
    distance = norm(vector);
    angle_z = atan2(vector[1], vector[0]);
    angle_y = atan2(sqrt(pow(vector[0], 2) + pow(vector[1], 2)), vector[2]);

