module pipe(x1, y1, z1, x2, y2, z2) {
    dx = x2 - x1;
    dy = y2 - y1;
    dz = z2 - z1;
    dist = sqrt(dx*dx + dy*dy + dz*dz);
    angle_y = atan2(sqrt(dx*dx + dy*dy), dz);
    angle_z = atan2(dy, dx);

    color("silver")
    translate([x1, y1, z1])
    rotate([0, angle_y, angle_z])
    cylinder(r=pipe_radius, h=dist, $fn=20);
}

