    pipe(40, -40, tank_height/2, 0, 40, tank_height/2);
    pipe(0, 40, tank_height/2, -40, -40, tank_height/2);

    // Vertical pipes
    pipe(-40, -40, 0, -40, -40, tank_height/2);
    pipe(40, -40, 0, 40, -40, tank_height/2);
