step_w = 20;
step_h = 5;
step_depth = 10;
radius = 40;

union() {
    // Rectangular block
    cube([block_w, block_d, block_h]);

    // Cube on top
    translate([block_w/2 - cube_size/2, block_d/2 - cube_size/2, block_h])
        cube([cube_size, cube_size, cube_size]);

    // Curved staircase
    for (i = [0 : stair_steps - 1]) {
        rotate([0, 0, i * 10])
        translate([radius, 0, i * step_h])
        cube([step_depth, step_w, step_h]);
    }

    // Railings
    for (i = [0 : stair_steps - 1]) {
        rotate([0, 0, i * 10])
        translate([radius + step_depth - 2, 0, i * step_h])
        cylinder(r=1, h=step_h + 10);

        rotate([0, 0, i * 10])
        translate([radius + step_depth - 2, step_w - 2, i * step_h])
        cylinder(r=1, h=step_h + 10);
    }

    // Handrail
    for (i = [0 : stair_steps - 1]) {
        hull() {
            rotate([0, 0, i * 10])
            translate([radius + step_depth - 2, 0, i * step_h + 10])
            sphere(r=1);
            rotate([0, 0, (i + 1) * 10])
            translate([radius + step_depth - 2, 0, (i + 1) * step_h + 10])
            sphere(r=1);
        }
    }
}

