module wireframe_box(size, thickness) {
    color([0.2, 0.2, 0.2])
    union() {
        for (x = [0, 1]) for (y = [0, 1])
            translate([x * size, y * size, 0]) rotate([0, 0, 0]) cylinder(h = size, r = thickness, $fn = 16);
        for (x = [0, 1]) for (z = [0, 1])
            translate([x * size, 0, z * size]) rotate([0, -90, 0]) cylinder(h = size, r = thickness, $fn = 16);
        for (y = [0, 1]) for (z = [0, 1])
            translate([0, y * size, z * size]) rotate([90, 0, 0]) cylinder(h = size, r = thickness, $fn = 16);
    }
}

module organic_form() {
    intersection() {
        cube([box_size, box_size, box_size]);
        difference() {
            union() {
                for (i = [0:15]) {
                    rotate([i * 23, i * 17, i * 11])
                    translate([box_size/2, box_size/2, box_size/2])
                    scale([1, 0.5, 1.5])
                    sphere(r = 20 + (i % 10), $fn = 32);
                }
            }
            union() {
                for (i = [0:8]) {
                    rotate([i * 45, i * 30, 0])
                    translate([box_size/2, box_size/2, box_size/2])
                    cylinder(h = box_size * 2, r = 10 + i, center = true, $fn = 24);
                }
                for (i = [0:5]) {
                    translate([i * 15, i * 10, 0])
                    cube([20, 20, box_size]);
                }
            }
        }
    }
}

union() {
    wireframe_box(box_size, wire_thickness);
    color([0.8, 0.3, 0.4, 0.9])
    organic_form();
}

