module container() {
    difference() {
        cylinder(r = container_radius, h = container_height, $fn = 64);
        translate([0, 0, wall_thickness])
            cylinder(r = container_radius - wall_thickness, h = container_height, $fn = 64);

        for (i = [0:3]) {
            rotate([0, 0, i * 90])
                translate([container_radius - wall_thickness, -notch_width / 2, 0])
                    cube([wall_thickness * 2, notch_width, container_height]);
        }
    }
}

union() {
    for (i = [0 : num_containers - 1]) {
        angle = i * (360 / num_containers);
        rotate([0, 0, angle])
            translate([ring_radius, 0, 0])
                container();
    }

    for (i = [0 : num_containers - 1]) {
        angle = i * (360 / num_containers);
        next_angle = (i + 1) * (360 / num_containers);

        rotate([0, 0, angle + (360 / num_containers) / 2])
            translate([ring_radius, 0, 0])
                rotate([0, 0, 90])
                    cube([wall_thickness * 2, wall_thickness * 2, container_height], center = true);
    }
}

