module platform(x, y, z) {
    translate([x, y, z])
    cube([platform_size, platform_size, platform_thickness], center=true);
}

module pillar(x, y, z) {
    translate([x, y, z])
    cylinder(r=pillar_radius, h=pillar_height, $fn=20);
}

module rod(p1, p2) {
    vector = p2 - p1;
    length = norm(vector);
    angle_z = atan2(vector.y, vector.x);
    angle_y = acos(vector.z / length);

    translate(p1)
    rotate([0, angle_y, angle_z])
    cylinder(r=rod_radius, h=length, $fn=12);
}

union() {
    // Platforms
    platform(0, 0, 0);
    platform(30, 30, 30);
    platform(-30, -30, 60);

    // Pillars
    pillar(-15, -15, 0);
    pillar(15, 15, 0);
    pillar(15, 15, 30);

    // Central Sphere
    sphere(r=sphere_radius, $fn=30);

    // Diagonal Rods
    rod([0, 0, 0], [30, 30, 30]);
    rod([30, 30, 30], [0, 0, 10]);
    rod([-30, -30, 60], [0, 0, 10]);
    rod([0, 0, 0], [-30, -30, 60]);
}

