module corner_strip() {
    union() {
        cube([corner_strip_width, corner_strip_thickness, cube_size], center=true);
        rotate([0, 0, 90])
            cube([corner_strip_width, corner_strip_thickness, cube_size], center=true);
        translate([0, 0, cube_size/2 + tab_size/2])
            cube([tab_size, tab_size, tab_size], center=true);
