    // Main Cube Body
    difference() {
        cube(cube_size, center=true);
        for (i = [0 : 3]) {
            rotate([0, 0, i * 90])
                translate([cube_size/2, 0, 0])
                    rotate([0, 90, 0])
                        ribbed_panel(cube_size - 4);
        }
    }

    // Corner Strips
    for (x = [-1, 1]) {
        for (y = [-1, 1]) {
            translate([x * (cube_size/2 - corner_strip_thickness/2), y * (cube_size/2 - corner_strip_thickness/2), 0])
