brick_cols = 5;
mortar_gap = 1;

module brick_wall(width, height, depth) {
    brick_w = (width - (brick_cols + 1) * mortar_gap) / brick_cols;
    brick_h = (height - (brick_rows + 1) * mortar_gap) / brick_rows;

    union() {
        for (r = [0 : brick_rows - 1]) {
            for (c = [0 : brick_cols - 1]) {
                offset = (r % 2 == 0) ? 0 : (brick_w / 2 + mortar_gap / 2);
                translate([c * (brick_w + mortar_gap) + offset - (width/2), r * (brick_h + mortar_gap) - (height/2), 0])
                cube([brick_w, brick_h, depth]);
            }
        }
    }
}

difference() {
    // Main hollow cube
    difference() {
        cube([cube_size, cube_size, cube_size], center = true);
        translate([wall_thickness, 0, 0])
        cube([cube_size, cube_size - 2 * wall_thickness, cube_size - 2 * wall_thickness], center = true);
    }

    // Remove front face
    translate([cube_size/2, 0, 0])
    cube([wall_thickness + 1, cube_size, cube_size], center = true);
}

// Add brick pattern to the remaining faces
intersection() {
    union() {
        // Back wall
        translate([-cube_size/2 + wall_thickness/2, 0, 0])
        rotate([0, 90, 0])
        brick_wall(cube_size, cube_size, wall_thickness);

        // Left wall
        translate([0, -cube_size/2 + wall_thickness/2, 0])
        rotate([90, 0, 0])
        brick_wall(cube_size, cube_size, wall_thickness);

        // Right wall
        translate([0, cube_size/2 - wall_thickness/2, 0])
        rotate([90, 0, 0])
        brick_wall(cube_size, cube_size, wall_thickness);

        // Top wall
        translate([0, 0, cube_size/2 - wall_thickness/2])
        brick_wall(cube_size, cube_size, wall_thickness);

        // Bottom wall
        translate([0, 0, -cube_size/2 + wall_thickness/2])
        brick_wall(cube_size, cube_size, wall_thickness);
    }
    cube([cube_size, cube_size, cube_size], center = true);
}

