    hull() {
        translate([0, 0, 0]) scale([1, 0.5, 0.5]) sphere(r = body_width / 2);
        translate([body_length * 0.6, 0, 0]) scale([0.5, 0.3, 0.3]) sphere(r = body_width / 2);
    }

    // Wings
    hull() {
        translate([body_length * 0.2, 0, 0]) cube([body_length * 0.3, 5, body_height * 0.8], center = true);
        translate([body_length * 0.2, wing_span / 2, 0]) cube([body_length * 0.2, 5, body_height * 0.2], center = true);
        translate([body_length * 0.2, -wing_span / 2, 0]) cube([body_length * 0.2, 5, body_height * 0.2], center = true);
    }

    // Tail Fin
    hull() {
        translate([body_length * 0.7, 0, 0]) cube([20, 5, 10], center = true);
        translate([body_length * 0.8, 0, tail_height]) cube([10, 5, 10], center = true);
    }

    // Landing Gear
    translate([body_length * 0.2, 15, -body_height * 0.4]) cylinder(h = gear_height, r = 3);
    translate([body_length * 0.2, -15, -body_height * 0.4]) cylinder(h = gear_height, r = 3);
    translate([body_length * 0.5, 0, -body_height * 0.4]) cylinder(h = gear_height, r = 3);

    // Cockpit
    translate([body_length * 0.1, 0, body_height * 0.2]) scale([1, 0.7, 0.8]) sphere(r = 12);
}

