// Parameters
mount_radius = 40;
mount_height = 20;
arm_length = 120;
arm_thickness = 8;
shade_radius = 30;
shade_height = 50;
num_arms = 5;

module arm() {
    // Curved arm using a series of segments
    union() {
        for (i = [0:10]) {
            rotate([0, i * 8, 0])
            translate([i * (arm_length / 10), 0, i * (arm_length / 20)])
            rotate([0, 90, 0])
            cylinder(r = arm_thickness / 2, h = arm_length / 10);
        }
    }
}

module shade() {
    difference() {
        cylinder(r = shade_radius, h = shade_height);
        translate([0, 0, 2])
        cylinder(r = shade_radius - 3, h = shade_height);
    }
}

// Central Mount
cylinder(r = mount_radius, h = mount_height);

// Arms and Shades
for (i = [0 : num_arms - 1]) {
    rotate([0, 0, i * (360 / num_arms)])
    translate([mount_radius * 0.5, 0, mount_height / 2]) {
        // Arm
        rotate([0, -30, 0])
        arm();

        // Shade
        translate([arm_length + 10, 0, arm_length / 2 - 10])
        rotate([0, 20, 0])
        shade();
    }
}

