module striped_wall(w, h, t) {
    difference() {
        cube([w, t, h]);
        for (i = [0 : stripe_spacing : w]) {
            translate([i, -1, 2]) cube([stripe_spacing / 2, t + 2, h - 4]);
        }
    }
}

union() {
    // Box Walls
    translate([0, 0, 0]) striped_wall(box_width, box_height, wall_thickness);
    translate([0, box_depth - wall_thickness, 0]) striped_wall(box_width, box_height, wall_thickness);
    rotate([0, 0, 90]) translate([0, -wall_thickness, 0]) striped_wall(box_depth, box_height, wall_thickness);
    rotate([0, 0, 90]) translate([0, -box_width, 0]) striped_wall(box_depth, box_height, wall_thickness);

    // Floor
    cube([box_width, box_depth, wall_thickness]);

    // Internal Grid
    difference() {
        union() {
            for (x = [grid_spacing : grid_spacing : box_width - grid_spacing]) {
                translate([x, wall_thickness, 0]) cube([grid_thickness, box_depth - 2 * wall_thickness, box_height / 2]);
            }
            for (y = [grid_spacing : grid_spacing : box_depth - grid_spacing]) {
                translate([wall_thickness, y, 0]) cube([box_width - 2 * wall_thickness, grid_thickness, box_height / 2]);
            }
        }
        // Cutout
        translate([box_width / 2 - cutout_size / 2, box_depth / 2 - cutout_size / 2, -1]) 
            cube([cutout_size, cutout_size, box_height]);
    }
}

