module segment(is_head = false) {
    union() {
        // Main body
        color("white")
        sphere(r = segment_radius);

        // Black accent ring
        color("black")
        rotate([0, 90, 0])
        cylinder(r = segment_radius + 0.2, h = 2, center = true);

        // Legs
        if (!is_head) {
            for (side = [-1, 1]) {
                color("white")
                translate([0, side * (segment_radius - 2), 0])
                rotate([side * 45, 0, 0])
                cylinder(r = leg_radius, h = leg_length);
            }
        }
    }
}

union() {
    for (i = [0 : num_segments - 1]) {
        translate([i * (segment_length * 0.8), 0, 0])
        rotate([0, 0, i * 5])
        segment(i == num_segments - 1);
    }

    // Eyes for the head
    translate([(num_segments - 1) * (segment_length * 0.8) + 7, 5, 3])
    color("black") sphere(r = 2);
    translate([(num_segments - 1) * (segment_length * 0.8) + 7, -5, 3])
    color("black") sphere(r = 2);
}

