rod_radius = 2;
rod_length = 50;
num_groups = 3;
rods_per_group = 5;
angle_spread = 30;

module rod(color_val) {
    color(color_val)
    rotate([0, 90, 0])
    cylinder(r = rod_radius, h = rod_length, $fn = 20);
}

union() {
    for (i = [0 : num_groups - 1]) {
        group_angle = i * (360 / num_groups);

        color_val = (i == 0) ? [1, 0, 0] : (i == 1) ? [0, 1, 0] : [0, 0, 1];

        rotate([0, 0, group_angle])
        for (j = [0 : rods_per_group - 1]) {
            rod_angle = (j - (rods_per_group - 1) / 2) * (angle_spread / rods_per_group);

            rotate([0, rod_angle, 0])
            rod(color_val);
        }
    }
}

