union() {
    // Wireframe outer shell
    difference() {
        cylinder(r = shell_radius, h = shell_height, center = true);
        cylinder(r = shell_radius - shell_thickness, h = shell_height + 1, center = true);

        // Create wireframe pattern
        for (i = [0 : 30 : 360]) {
            rotate([0, 0, i])
            translate([shell_radius, 0, 0])
            cube([shell_thickness * 2, 5, shell_height + 1], center = true);
        }
    }

    // Central hub
    cylinder(r = hub_radius, h = shell_height, center = true);

    // Three large vertical cylinders
    for (i = [0 : 120 : 359]) {
        rotate([0, 0, i])
        translate([30, 0, 0]) {
            // Vertical cylinder
            cylinder(r = inner_cylinder_radius, h = shell_height, center = true);

            // Connecting rod to hub
            rotate([0, 90, 0])
            cylinder(r = rod_thickness, h = 30 - hub_radius, center = true);
        }
    }
}

