grid_size = 60;
grid_spacing = 10;
base_thickness = 2;
num_cylinders = 8;
num_particles = 40;

module wavy_base() {
    for (x = [0:grid_spacing:grid_size]) {
        for (y = [0:grid_spacing:grid_size]) {
            translate([x, y, 0])
            cylinder(r = 3, h = base_thickness + 5 * sin(x * 10) * cos(y * 10));
        }
    }
}

module main_composition() {
    union() {
        // Cylindrical shapes
        for (i = [1:num_cylinders]) {
            translate([i * 6, i * 6, 0])
            rotate([0, 0, i * 20])
            color([0, 0.5, 0.5])
            cylinder(r = 4 - (i * 0.2), h = 20 + (i * 5));
        }

        // Spherical elements
        for (i = [1:5]) {
            translate([20 + i * 5, 20, 30 + i * 2])
            color([0, 0.6, 0.6])
            sphere(r = 5 - i * 0.5);
        }

        // Dissolving particles
        for (i = [0:num_particles]) {
            translate([
                30 + 20 * sin(i * 30), 
                30 + 20 * cos(i * 30), 
                40 + i * 0.5
            ])
            color([0, 0.7, 0.7])
            sphere(r = 1.5 - (i * 0.02));
        }
    }
}

union() {
    color([0, 0.4, 0.4])
    wavy_base();

    translate([5, 5, base_thickness])
    main_composition();
}

