module pentagon() {
    linear_extrude(height = radius * 0.2)
    for (i = [0:4]) {
        rotate(i * 72)
        translate([radius * 0.15, 0, 0])
        circle(r = edge_len * 0.6, $fn = 5);
    }
}

module hexagon() {
    linear_extrude(height = radius * 0.2)
    circle(r = edge_len * 0.7, $fn = 6);
}

module soccer_ball() {
    union() {
        sphere(r = radius, $fn = 100);

        // Distribute patterns on the surface
        // Icosahedral symmetry approximation
        for (i = [0:11]) {
            rotate([0, 0, i * 30])
            rotate([63.43, 0, 0])
            translate([0, 0, radius - 2])
            color("white")
            pentagon();
        }

        for (i = [0:19]) {
            rotate([0, 0, i * 18])
            rotate([37.38, 0, 0])
            translate([0, 0, radius - 2])
            color("black")
            hexagon();
        }
    }
}

