    translate([0, (fixture_depth / 2) + (mount_thickness / 2) - (fixture_depth - wall_thickness), 0])
    rotate([90, 0, 0])
    cylinder(h = wall_thickness, r = tube_radius, $fn = 100);

    // Bottom cap
