module building(w, d, h) {
    union() {
        color([0.4, 0.4, 0.4]) cube([w, d, h]);
        color([0.8, 0.7, 0.5]) translate([0, 0, h]) rotate([0, 0, 0]) 
            polyhedron(
                points=[[0,0,0], [w,0,0], [w,d,0], [0,d,0], [w/2,d/2,h/2]],
                faces=[[0,1,2,3], [0,1,4], [1,2,4], [2,3,4], [3,0,4]]
            );
    }
}

union() {
    color([0.2, 0.2, 0.2]) cube([base_width, base_depth, base_height]);

    for (i = [0 : num_buildings - 1]) {
        x_pos = (i % 5) * 18 + 5;
        y_pos = floor(i / 5) * 25 + 5;
        w = 10 + (i % 3) * 2;
        d = 10 + (i % 2) * 5;
        h = 10 + (i % 4) * 5;

        translate([x_pos, y_pos, base_height]) 
            building(w, d, h);
    }
}

