base_radius = 50;
top_radius = 20;
height = 80;
chamfer_size = 2;
segments = 6;

module hexagon(radius) {
    cylinder(r = radius, h = 0.1, $fn = segments);
}

union() {
    hull() {
        hexagon(base_radius);
        translate([0, 0, height])
        rotate([0, 0, 30])
        hexagon(top_radius);
    }

    // Chamfering edges using Minkowski with a small sphere
    // Note: Minkowski is slow, using hull-based approach for performance
    difference() {
        hull() {
            hexagon(base_radius);
            translate([0, 0, height])
            rotate([0, 0, 30])
            hexagon(top_radius);
        }

        // Simple edge chamfering via subtraction
        for (i = [0:segments-1]) {
            angle = i * 360 / segments;
            x1 = base_radius * cos(angle);
            y1 = base_radius * sin(angle);
            x2 = top_radius * cos(angle + 30);
            y2 = top_radius * sin(angle + 30);

            hull() {
                translate([x1, y1, 0]) sphere(chamfer_size, $fn=12);
                translate([x2, y2, height]) sphere(chamfer_size, $fn=12);
            }
        }
    }
}

