sphere_radius = 10;
rod_radius = 3;
rod_length = 40;
dist = rod_length / sqrt(2);

module rod(p1, p2) {
    v = p2 - p1;
    l = norm(v);
    rotate([0, acos(v.z / l), atan2(v.y, v.x)])
        cylinder(r = rod_radius, h = l, $fn = 20);
}

union() {
    // Spheres at vertices of an octahedron
    points = [
        [dist, 0, 0], [-dist, 0, 0],
        [0, dist, 0], [0, -dist, 0],
        [0, 0, dist], [0, 0, -dist]
    ];

    for (p = points) {
        color([abs(p.x)/dist, abs(p.y)/dist, abs(p.z)/dist])
            translate(p) sphere(r = sphere_radius, $fn = 30);
    }

    // Rods connecting the spheres
    color("silver") {
        rod(points[0], points[2]);
        rod(points[0], points[3]);
        rod(points[0], points[4]);
        rod(points[0], points[5]);

        rod(points[1], points[2]);
        rod(points[1], points[3]);
        rod(points[1], points[4]);
        rod(points[1], points[5]);

        rod(points[2], points[4]);
        rod(points[2], points[5]);
        rod(points[3], points[4]);
        rod(points[3], points[5]);
    }
}

