difference() {
    // Main box body
    cube([box_width, box_depth, box_height]);

    // Hollow out the inside
    translate([wall_thickness, wall_thickness, wall_thickness])
    cube([box_width - 2 * wall_thickness, box_depth - wall_thickness, box_height - 2 * wall_thickness]);

    // Recessed front panel
    translate([wall_thickness, 0, wall_thickness])
    cube([box_width - 2 * wall_thickness, recess_depth, box_height - 2 * wall_thickness]);

    // Ventilation slots on the right side
    for (i = [0 : num_slots - 1]) {
        translate([box_width - wall_thickness, 10 + i * slot_spacing, (box_height - slot_height) / 2])
        cube([wall_thickness * 2, slot_width, slot_height]);
    }
}

