module container() {
    difference() {
        cylinder(r = container_radius, h = container_height, $fn = 100);
        translate([0, 0, wall_thickness])
            cylinder(r = container_radius - wall_thickness, h = container_height, $fn = 100);
    }

    for (i = [1 : ridge_count]) {
        translate([0, 0, (container_height / (ridge_count + 1)) * i])
            rotate_extrude($fn = 100)
                translate([container_radius - 0.5, 0, 0])
                    circle(r = ridge_height, $fn = 20);
    }

    for (i = [0 : 3]) {
        rotate([0, 0, i * 90])
            translate([container_radius - 1, -bracket_width / 2, 0])
                union() {
                    cube([bracket_depth, bracket_width, container_height]);
                    translate([bracket_depth, 0, container_height])
                        rotate([0, 45, 0])
                            cube([bracket_depth, bracket_width, bracket_depth]);
                }
    }
}

module triangular_patterns() {
    for (i = [0 : 12]) {
        rotate([0, 0, i * 30])
            translate([container_radius - 1, 0, container_height / 2])
                rotate([90, 0, 90])
                    linear_extrude(height = 2)
                        polygon([[0, 0], [10, 0], [5, 10]]);
    }
}

union() {
    container();
    triangular_patterns();
}

