module curved_link(r_loop, r_link) {
    rotate_extrude(angle = 180)
    translate([r_loop, 0, 0])
    circle(r = r_link);
}

union() {
    for (i = [0 : num_spheres - 1]) {
        angle = i * (360 / num_spheres);

        // Spherical cores
        rotate([0, 0, angle])
        translate([loop_radius, 0, 0])
        sphere(r = core_radius);

        // Interconnecting loops
        rotate([0, 0, angle])
        translate([loop_radius, 0, 0])
        rotate([0, 90, 0])
        curved_link(loop_radius, link_radius);
    }

    // Central core
    sphere(r = core_radius * 0.8);
}

