union() {
    // Main rectangular block
    cube([block_length, block_width, block_height], center = true);

    // Elevated central protrusion
    translate([0, 0, (block_height + protrusion_height) / 2])
    cube([protrusion_length, protrusion_width, protrusion_height], center = true);

    // Vertical cylindrical supports beneath
    for (i = [0 : num_supports - 1]) {
        x_pos = -block_length / 2 + (block_length / (num_supports + 1)) * (i + 1);

        // Supports on the bottom
