rod_radius = 1.5;
num_rods = 6;

union() {
    // Central solid sphere
    sphere(r = sphere_radius, $fn = 50);

    // Hexagonal plates
    for (z = [-rod_height/2, rod_height/2]) {
        translate([0, 0, z])
        linear_extrude(height = plate_thickness, center = true)
        circle(r = plate_radius, $fn = 6);
    }

    // Vertical rods connecting plates
    for (i = [0 : num_rods - 1]) {
        angle = i * (360 / num_rods);
        x = (plate_radius - 2) * cos(angle);
        y = (plate_radius - 2) * sin(angle);

        translate([x, y, 0])
        cylinder(r = rod_radius, h = rod_height, center = true, $fn = 12);
    }

    // Wireframe edges for the polyhedron (connecting vertices)
    for (i = [0 : num_rods - 1]) {
        angle1 = i * (360 / num_rods);
        angle2 = (i + 1) * (360 / num_rods);

        x1 = plate_radius * cos(angle1);
        y1 = plate_radius * sin(angle1);
        x2 = plate_radius * cos(angle2);
        y2 = plate_radius * sin(angle2);

        // Top edges
        translate([0, 0, rod_height/2])
        rotate([0, 0, angle1])
        translate([(x1+x2)/2, (y1+y2)/2, 0])
        rotate([0, 90, 0])
        cylinder(r = 0.8, h = 25, center = true, $fn = 8);

        // Bottom edges
        translate([0, 0, -rod_height/2])
        rotate([0, 0, angle1])
        translate([(x1+x2)/2, (y1+y2)/2, 0])
        rotate([0, 90, 0])
        cylinder(r = 0.8, h = 25, center = true, $fn = 8);
    }
}

