module wireframe_sphere(r, spacing) {
    intersection() {
        sphere(r = r, $fn = 50);
        union() {
            for (i = [-r:spacing:r]) {
                translate([0, 0, i]) rotate([0, 90, 0]) cylinder(r = pattern_thickness, h = 2 * r, center = true, $fn = 12);
                translate([0, i, 0]) rotate([90, 0, 0]) cylinder(r = pattern_thickness, h = 2 * r, center = true, $fn = 12);
                translate([i, 0, 0]) rotate([0, 0, 0]) cylinder(r = pattern_thickness, h = 2 * r, center = true, $fn = 12);
            }
        }
    }
}

module tapered_cylinder(r1, r2, h) {
    cylinder(r1 = r1, r2 = r2, h = h, $fn = 50);
}

union() {
    // Solid tapered cylinder
    tapered_cylinder(base_radius, top_radius, height);

    // Wireframe sphere on top
    translate([0, 0, height + sphere_radius]) {
        wireframe_sphere(sphere_radius, pattern_spacing);
    }

    // Pattern wrapping around the tapered cylinder
    intersection() {
        tapered_cylinder(base_radius + 0.5, top_radius + 0.5, height);
        union() {
            for (a = [0:20:360]) {
                rotate([0, 0, a]) translate([base_radius, 0, 0]) 
                rotate([0, atan((base_radius - top_radius) / height), 0])
                cube([pattern_thickness, pattern_thickness, height * 1.2], center = true);
            }
            for (z = [0:pattern_spacing:height]) {
                translate([0, 0, z]) rotate_extrude($fn = 50) translate([base_radius - (z/height)*(base_radius-top_radius), 0, 0]) circle(r = pattern_thickness/2, $fn = 12);
            }
        }
    }
}

