module plant_arrangement() {
    for (i = [0 : plant_count - 1]) {
        angle = i * (360 / plant_count);
        x = ring_radius * cos(angle);
        y = ring_radius * sin(angle);

        color_choice = (i % 3 == 0) ? "green" : (i % 3 == 1) ? "red" : "yellow";

        translate([x, y, box_height/2 - 10])
            plant(color_choice);
    }
}

