module petal() {
    intersection() {
        sphere(r = sphere_radius + 5);
        translate([0, 0, sphere_radius])
        rotate([90, 0, 0])
        scale([1, 1.5, 0.2])
        sphere(r = petal_width);
    }
}

color([0.8, 0.9, 1.0, 0.6]) {
    difference() {
        sphere(r = sphere_radius);

        union() {
            for (i = [0 : petal_count]) {
                phi = acos(-1 + (2 * i) / petal_count);
                theta = sqrt(petal_count * PI) * phi;

                x = sphere_radius * sin(phi) * cos(theta);
                y = sphere_radius * sin(phi) * sin(theta);
                z = sphere_radius * cos(phi);

                rotate([0, 0, theta])
                rotate([0, phi, 0])
                translate([0, 0, sphere_radius - 1])
                rotate([90, 0, 0])
                scale([1, 1.2, 0.5])
                sphere(r = petal_width * 0.8);
            }
        }
    }

    for (i = [0 : petal_count]) {
        phi = acos(-1 + (2 * i) / petal_count);
        theta = sqrt(petal_count * PI) * phi;

        x = sphere_radius * sin(phi) * cos(theta);
        y = sphere_radius * sin(phi) * sin(theta);
        z = sphere_radius * cos(phi);

        rotate([0, 0, theta])
        rotate([0, phi, 0])
        translate([0, 0, sphere_radius - 2])
        rotate([90, 0, 0])
        scale([1, 1.2, 0.5])
        sphere(r = petal_width * 0.8);
    }
}

