module star_prism(points, radius, height) {
    linear_extrude(height = height) {
        rotate([0, 0, 90])
        union() {
            for (i = [0 : points - 1]) {
                rotate([0, 0, i * 360 / points])
                polygon([[0, 0], [radius, 0], [radius * 0.4, radius * 0.3], [radius, radius * 0.6], [0, radius * 0.8]]);
            }
        }
    }
}

union() {
    // Two spheres
    translate([0, 0, 30]) sphere(r = sphere_radius, $fn = 50);
    translate([0, 0, -30]) sphere(r = sphere_radius, $fn = 50);

    // Central star
    translate([0, 0, -star_height / 2]) star_prism(star_points, star_radius, star_height);

    // Connecting rods and components
    for (i = [0 : 3]) {
        rotate([0, 0, i * 90]) {
            translate([15, 0, 0]) {
                rotate([0, 90, 0]) cylinder(r = rod_radius, h = rod_length, $fn = 20);
                translate([rod_length, 0, 0]) {
                    cube([comp_size, comp_size, comp_size], center = true);
                    translate([0, 0, comp_size]) cylinder(r = rod_radius * 2, h = comp_size, $fn = 20);
