        phi = acos(-1 + (2 * i) / num_spikes);
        theta = sqrt(num_spikes * PI) * phi;

        x = (sphere_radius + spike_height / 2) * sin(phi) * cos(theta);
        y = (sphere_radius + spike_height / 2) * sin(phi) * sin(theta);
        z = (sphere_radius + spike_height / 2) * cos(phi);

        translate([x, y, z])
        rotate([0, (phi * 180 / PI), (theta * 180 / PI)])
        rotate([0, 90, 0])
        cylinder(r1 = spike_base / 2, r2 = 0, h = spike_height, $fn = 20);
