            cube([beam_thickness, jaw_depth, beam_thickness]);

        // Slider
        translate([30, -(slider_width - beam_width)/2, -1.5])
            difference() {
                cube([slider_width, slider_width, slider_thickness]);
                // Cutout for beam
                translate([-gap, (slider_width - beam_width)/2, (slider_thickness - beam_thickness)/2])
                    cube([slider_width + 2*gap, beam_width, beam_thickness]);
            }

        // Sliding jaw
        translate([30, -jaw_depth, 0])
            cube([beam_thickness, jaw_depth, beam_thickness]);

        // Depth rod
        translate([30 + beam_thickness/2, 0, 0])
            cube([1, jaw_depth, 1]);

        // Scale markings
        for (i = [0:10:140]) {
            translate([i, beam_width, 0])
                cube([0.5, 3, beam_thickness]);
        }
    }
}

