module polyhedral_sphere() {
    intersection() {
        sphere(r = sphere_radius, $fn = 20);
        union() {
            for (i = [0:10:180]) {
                rotate([0, i, 0])
                cube([sphere_radius * 2, sphere_radius * 0.1, sphere_radius * 2], center = true);
            }
            for (i = [0:10:180]) {
                rotate([i, 0, 0])
                cube([sphere_radius * 0.1, sphere_radius * 2, sphere_radius * 2], center = true);
            }
        }
    }
}

module wireframe_cone() {
    color([0.5, 0.5, 0.5])
    union() {
        for (a = [0:30:359]) {
            rotate([0, 0, a])
            translate([0, 0, 0])
            rotate([0, -atan(cone_radius / cone_height), 0])
            cylinder(r = wire_thickness / 2, h = sqrt(pow(cone_radius, 2) + pow(cone_height, 2)), $fn = 8);
        }
        for (h = [0:cone_height/5:cone_height]) {
            translate([0, 0, h])
            rotate_extrude(angle = 360, $fn = 60)
            translate([(h / cone_height) * cone_radius, 0, 0])
            circle(r = wire_thickness / 2, $fn = 8);
        }
    }
}

union() {
    color("black")
    polyhedral_sphere();

    color("white")
    intersection() {
        sphere(r = sphere_radius, $fn = 20);
        union() {
            for (i = [0:45:360]) {
                rotate([i, i/2, 0])
                cube([sphere_radius * 0.5, sphere_radius * 0.5, sphere_radius * 2], center = true);
            }
        }
    }

    wireframe_cone();
}

