    [3, 9, 4], [3, 4, 2], [3, 2, 6], [3, 6, 8], [3, 8, 9],
    [5, 4, 9], [11, 2, 4], [10, 6, 2], [7, 8, 6], [1, 9, 8]
];

function normalize(v) = v / norm(v);

function get_mid(v1, v2) = normalize((v1 + v2) / 2) * sphere_radius;

module triangle(p1, p2, p3, color_val) {
    color("white")
    hull() {
        sphere(r = edge_thickness);
        translate(p1) sphere(r = edge_thickness);
        translate(p2) sphere(r = edge_thickness);
        translate(p3) sphere(r = edge_thickness);
    }

    color(color_val)
    polyhedron(
        points = [p1 * (1 - panel_inset/sphere_radius), p2 * (1 - panel_inset/sphere_radius), p3 * (1 - panel_inset/sphere_radius)],
        faces = [[0, 1, 2]]
    );
}

module subdivide(p1, p2, p3, depth) {
    if (depth == 0) {
        triangle(p1, p2, p3, (p1[0]+p2[0]+p3[0] > 0) ? "yellow" : "black");
    } else {
        m1 = get_mid(p1, p2);
        m2 = get_mid(p2, p3);
        m3 = get_mid(p3, p1);
        subdivide(p1, m1, m3, depth - 1);
        subdivide(m1, p2, m2, depth - 1);
        subdivide(m3, m2, p3, depth - 1);
        subdivide(m1, m2, m3, depth - 1);
    }
}

for (f = base_faces) {
    subdivide(base_verts[f[0]] * sphere_radius, base_verts[f[1]] * sphere_radius, base_verts[f[2]] * sphere_radius, subdivisions);
}

