        cube([bracket_size, base_depth, bracket_size]);
        translate([0, -1, 0])
        rotate([-90, 0, 0])
        linear_extrude(base_depth + 2)
        polygon([[0, 0], [bracket_size, 0], [0, bracket_size]]);
