    translate([cantilever_length - 15, 10, base_thickness + cantilever_thickness])
    cylinder(r = spacer_radius, h = spacer_height, $fn = 32);

    translate([cantilever_length - 15, base_depth - 10, base_thickness + cantilever_thickness])
    cylinder(r = spacer_radius, h = spacer_height, $fn = 32);
}

