ball_radius = 21.35;
dimple_radius = 2.5;
dimple_depth = 0.8;
num_dimples = 300;

$fn = 100;

module golf_ball() {
    difference() {
        sphere(r = ball_radius);

        for (i = [0 : num_dimples]) {
            phi = acos(-1 + (2 * i) / num_dimples);
            theta = sqrt(num_dimples * PI) * phi;

            x = (ball_radius) * sin(phi) * cos(theta);
            y = (ball_radius) * sin(phi) * sin(theta);
            z = (ball_radius) * cos(phi);

            translate([x, y, z])
            rotate([0, (phi * 180 / PI), (theta * 180 / PI)])
            translate([0, 0, ball_radius - dimple_depth])
            sphere(r = dimple_radius);
        }
    }
}

