module soccer_ball() {
    phi = (1 + sqrt(5)) / 2;
    vertices = [
        [0, 1, phi], [0, 1, -phi], [0, -1, phi], [0, -1, -phi],
        [1, phi, 0], [1, -phi, 0], [-1, phi, 0], [-1, -phi, 0],
        [phi, 0, 1], [phi, 0, -1], [-phi, 0, 1], [-phi, 0, -1]
    ];

    faces = [
        [0, 8, 4, 6, 10], [0, 10, 11, 2, 8], [8, 2, 5, 9, 4],
        [4, 9, 1, 7, 6], [6, 7, 11, 10, 6], [1, 3, 5, 2, 11],
        [3, 1, 9, 5, 3]
    ];

    intersection() {
        sphere(r = radius, $fn = 100);
        union() {
            for (v = vertices) {
                rotate([0, 0, 0]) 
                hull() {
                    sphere(r = radius - panel_thickness, $fn = 50);
                    sphere(r = radius, $fn = 50);
                }
            }
        }
    }
}

