        // Wear and tear on edges
        for (i = [0:8]) {
            translate([
                rands(-cube_size/2, cube_size/2, 1)[0],
                rands(-cube_size/2, cube_size/2, 1)[0],
                rands(-cube_size/2, cube_size/2, 1)[0]
