module twisted_torus() {
    difference() {
        union() {
            for (i = [0 : 3]) {
                rotate([0, 0, i * 90])
                translate([loop_radius, 0, 0])
                sphere(r = sphere_radius);
            }

            for (a = [0 : 0.1 : 360]) {
                rotate([0, 0, a])
                translate([loop_radius, 0, sin(a * twist_factor) * 5])
                rotate([0, 90, 0])
                cylinder(r = tube_radius, h = 1);
            }
        }

        for (a = [0 : 0.1 : 360]) {
            rotate([0, 0, a])
            translate([loop_radius, 0, sin(a * twist_factor) * 5])
            rotate([0, 90, 0])
            cylinder(r = tube_radius - 1, h = 1.2);
        }
    }
}

