module pipe_segment(length) {
    rotate([0, 90, 0])
    cylinder(r = pipe_radius, h = length, center = true);
}

module end_cap() {
    cylinder(r = cap_radius, h = cap_height);
}

module valve_control() {
    union() {
        cylinder(r = valve_radius / 2, h = valve_height);
        translate([0, 0, valve_height])
        cylinder(r = valve_radius, h = 3);
        translate([0, 0, valve_height + 1.5])
        cube([valve_radius * 2.5, 4, 3], center = true);
    }
}

union() {
    // Main pipe
    difference() {
        pipe_segment(pipe_length);
        rotate([0, 90, 0])
        cylinder(r = pipe_radius - 2, h = pipe_length + 2, center = true);
    }

    // End caps
    translate([pipe_length / 2, 0, 0])
    rotate([0, 90, 0])
    end_cap();

    translate([-pipe_length / 2 - cap_height, 0, 0])
    rotate([0, -90, 0])
    end_cap();

    // Valves
    translate([0, 0, pipe_radius])
    valve_control();

    translate([pipe_length / 4, 0, pipe_radius])
    valve_control();

    translate([-pipe_length / 4, 0, pipe_radius])
    valve_control();

    // Valve mounts
    translate([0, 0, pipe_radius / 2])
    cylinder(r = valve_radius + 2, h = pipe_radius / 2);

    translate([pipe_length / 4, 0, pipe_radius / 2])
    cylinder(r = valve_radius + 2, h = pipe_radius / 2);

    translate([-pipe_length / 4, 0, pipe_radius / 2])
    cylinder(r = valve_radius + 2, h = pipe_radius / 2);
}

