strut_radius = 2;
sphere_radius = 4;

module strut(p1, p2) {
    hull() {
        translate(p1) sphere(r = strut_radius, $fn = 20);
        translate(p2) sphere(r = strut_radius, $fn = 20);
    }
}

module node(p) {
    sphere(r = sphere_radius, $fn = 30);
}

// Icosahedron vertices (Golden Ratio based)
phi = (1 + sqrt(5)) / 2;
v = [
    [0, 1, phi], [0, -1, phi], [0, 1, -phi], [0, -1, -phi],
    [1, phi, 0], [-1, phi, 0], [1, -phi, 0], [-1, -phi, 0],
    [phi, 0, 1], [-phi, 0, 1], [phi, 0, -1], [-phi, 0, -1]
];

scaled_v = [for (p = v) [p[0] * edge_length / 2, p[1] * edge_length / 2, p[2] * edge_length / 2]];

// Generate nodes
for (p = scaled_v) {
    color([0.2, 0.6, 0.9]) node(p);
}

// Generate struts
for (i = [0 : len(scaled_v) - 1]) {
    for (j = [i + 1 : len(scaled_v) - 1]) {
        dist = sqrt(pow(scaled_v[i][0] - scaled_v[j][0], 2) + 
                    pow(scaled_v[i][1] - scaled_v[j][1], 2) + 
                    pow(scaled_v[i][2] - scaled_v[j][2], 2));

        // Threshold for icosahedron edge length
        if (dist > (edge_length * 0.9) && dist < (edge_length * 1.1)) {
            color([0.9, 0.3, 0.3]) strut(scaled_v[i], scaled_v[j]);
        }
    }
}

