module threaded_cylinder(r, h, pitch, depth) {
    union() {
        cylinder(r = r, h = h);
        for (i = [0 : 0.5 : h / pitch]) {
            translate([0, 0, i * pitch])
            rotate_extrude()
            translate([r - depth, 0, 0])
            circle(r = pitch / 4);
