module rod(p1, p2) {
    v = p2 - p1;
    l = norm(v);
    rotate([0, atan2(sqrt(v.x*v.x + v.y*v.y), v.z), atan2(v.y, v.x)])
    cylinder(r = rod_radius, h = l);
}

union() {
    // Central spheres
    s1 = [0, 0, -center_dist/2];
    s2 = [0, 0, center_dist/2];

    sphere(r = sphere_radius);
    translate(s2) sphere(r = sphere_radius);
    rod(s1, s2);

    // Outer spheres for each central sphere
    for (i = [0:2]) {
        angle = i * 120;

        // Outer spheres for bottom center
        pos1 = [outer_dist * cos(angle), outer_dist * sin(angle), -center_dist/2 + 20];
        translate(pos1) sphere(r = sphere_radius);
        rod(s1, pos1);

        // Outer spheres for top center
        pos2 = [outer_dist * cos(angle), outer_dist * sin(angle), center_dist/2 - 20];
        translate(pos2) sphere(r = sphere_radius);
        rod(s2, pos2);
    }
}

