module torus_knot() {
    union() {
        for (i = [0 : segments]) {
            t = i / segments * 360 * q;

            // Parametric equations for a torus knot
            x = (major_radius + minor_radius * cos(p / q * t)) * cos(t);
            y = (major_radius + minor_radius * cos(p / q * t)) * sin(t);
            z = minor_radius * sin(p / q * t);

            translate([x, y, z])
            sphere(r = thickness);
        }
    }
}

difference() {
    // The knot structure
    torus_knot();

    // Hollow center
    sphere(r = major_radius - minor_radius * 2);
}

