union() {
    // Triangular base
    linear_extrude(height = base_height) {
        polygon(points=[[0, 0], [base_side, 0], [base_side/2, base_side * 0.866]]);
    }

    // Four red cylindrical connectors
    color("red") {
        translate([20, 20, base_height]) cylinder(r = connector_r, h = connector_h);
        translate([80, 20, base_height]) cylinder(r = connector_r, h = connector_h);
        translate([50, 60, base_height]) cylinder(r = connector_r, h = connector_h);
        translate([50, 20, base_height]) cylinder(r = connector_r, h = connector_h);
    }

    // Hexagonal bolts
    for (i = [0:2]) {
        translate([25 + i * 25, 10, base_height])
        cylinder(r = bolt_r, h = 5, $fn = 6);
    }

    // Threaded pipe fitting
    difference() {
        translate([50, 40, base_height]) cylinder(r = pipe_r, h = 10);
        translate([50, 40, base_height]) cylinder(r = pipe_r - 2, h = 12);
    }

    // Embossed number 32
    color("silver")
    translate([40, 5, base_height])
    linear_extrude(height = 2)
    text("32", size = text_size, font = "Liberation Sans:style=Bold");
}

