color([1, 0.9, 0]) {
    difference() {
        // Base irregular block using hull of shifted primitives
        hull() {
            cube([block_width, block_depth, block_height]);
            translate([5, 5, 5]) 
                scale([1.2, 0.8, 1.1]) 
                    cube([block_width, block_depth, block_height]);
            translate([block_width, 0, 0]) 
                rotate([0, 15, 0]) 
                    cube([5, block_depth, block_height + 10]);
        }

        // Protruding notch (subtractive)
        translate([block_width - 5, block_depth / 2 - notch_size / 2, block_height - notch_size])
            cube([10, notch_size, notch_size]);

        // Asymmetrical edge cut
        rotate([0, 20, 0])
            translate([-10, -5, -5])
                cube([15, block_depth + 10, block_height + 10]);
    }
}

