module clamp(x_pos) {
    translate([x_pos, base_d/2 - 10, base_h]) {
        difference() {
            cube([clamp_w, 20, clamp_h]);
            translate([clamp_w/2, 10, clamp_h/2]) rotate([90, 0, 0]) cylinder(r = 12, h = 25, $fn = 50);
            translate([5, -1, 5]) cube([10, 22, 5]);
