module segment(angle_start, angle_end) {
    intersection() {
        difference() {
            sphere(r = outer_radius);
            sphere(r = inner_radius);
        }
        linear_extrude(height = outer_radius * 2, center = true) {
            polygon([
                [0, 0],
                [outer_radius * cos(angle_start), outer_radius * sin(angle_start)],
                [outer_radius * cos(angle_end), outer_radius * sin(angle_end)]
            ]);
        }
    }
}

union() {
    for (i = [0 : segments - 1]) {
        color([0.96, 0.96, 0.86]) 
        rotate([0, 0, i * (360 / segments)]) 
        segment(5, (360 / segments) - 5);
    }

    color([0.2, 0.15, 0.1])
    difference() {
        sphere(r = inner_radius - 0.5);
        sphere(r = inner_radius - shell_thickness);
