module peaked_roof(size) {
    union() {
        cube([size, size, size], center=true);
        translate([0, 0, size/2])
        rotate([0, 0, 45])
        cylinder(h=size/2, r1=size*0.7, r2=0, $fn=4);
    }
}

module open_frame(size) {
    thickness = 2;
    difference() {
        cube([size, size, size], center=true);
        union() {
            cube([size - thickness*2, size + 1, size - thickness*2], center=true);
            cube([size + 1, size - thickness*2, size - thickness*2], center=true);
            cube([size - thickness*2, size - thickness*2, size + 1], center=true);
        }
    }
}

union() {
    // Base
    cube([base_width, base_depth, base_height]);

    // Array of structures
    for (x = [0 : grid_size - 1]) {
        for (y = [0 : grid_size - 1]) {
            translate([15 + x * spacing, 15 + y * spacing, base_height + box_size/2]) {
                if ((x + y) % 2 == 0) {
                    peaked_roof(box_size);
                } else {
                    open_frame(box_size);
                }
            }
        }
    }
}

