module twisted_rod() {
    union() {
        for (i = [0 : segments]) {
            t = i / segments;
            z = t * rod_length;
            angle = t * twist_angle;
            radius = rod_radius * (1 - (t * 0.5));

            translate([sin(angle) * 5, cos(angle) * 5, z])
            rotate([0, 0, angle])
            union() {
                cylinder(r = radius, h = rod_length / segments, $fn = 16);

                // Texture: small spheres along the surface
                if (i % 5 == 0) {
                    translate([radius, 0, 0])
                    sphere(r = 1, $fn = 8);
                }
            }
        }

        // Loop at the top
        translate([sin(twist_angle) * 5, cos(twist_angle) * 5, rod_length])
        rotate([0, 0, twist_angle])
        translate([0, 0, loop_radius])
        rotate([90, 0, 0])
        difference() {
            torus(loop_radius, rod_radius * 0.5);
            translate([0, -loop_radius * 2, 0])
            cube([loop_radius * 2, loop_radius * 4, loop_radius * 2]);
        }
    }
}

