    cube([wall_width/brick_cols - mortar_gap, wall_height/brick_rows - mortar_gap, wall_depth]);
}

module wall_base() {
    union() {
        for (y = [0 : brick_rows - 1]) {
            for (x = [0 : brick_cols - 1]) {
                translate([x * (wall_width/brick_cols) + (y % 2 == 0 ? 0 : (wall_width/brick_cols)/2), y * (wall_height/brick_rows), 0])
                brick();
            }
        }
    }
}

module molding() {
    translate([0, wall_height - 5, wall_depth])
    rotate([90, 0, 0])
    linear_extrude(height = 5)
    polygon([[0,0], [wall_width, 0], [wall_width-5, 5], [5, 5]]);
}

module damage() {
    union() {
        translate([20, 30, 5]) sphere(r = 8, $fn = 20);
        translate([60, 50, 5]) sphere(r = 12, $fn = 20);
        translate([40, 10, 5]) cube([15, 15, 10]);
    }
}

difference() {
    union() {
        wall_base();
        molding();
    }
    damage();
}

