ring_radius = 50;
num_shapes = 8;
shape_size = 10;

module shape(i) {
    if (i == 0) cube([shape_size, shape_size, shape_size], center=true);
    else if (i == 1) sphere(r=shape_size/1.5, $fn=20);
    else if (i == 2) cylinder(r=shape_size/2, h=shape_size, center=true, $fn=6);
    else if (i == 3) scale([1, 1.5, 1]) sphere(r=shape_size/2, $fn=20);
    else if (i == 4) cylinder(r=shape_size/2, h=shape_size, center=true, $fn=3);
    else if (i == 5) cube([shape_size, shape_size/2, shape_size*1.5], center=true);
    else if (i == 6) rotate([45, 0, 0]) cube([shape_size, shape_size, shape_size], center=true);
    else cylinder(r1=shape_size/2, r2=0, h=shape_size, center=true, $fn=20);
}

union() {
    for (i = [0 : num_shapes - 1]) {
        rotate([0, 0, i * (360 / num_shapes)])
        translate([ring_radius, 0, 0])
        shape(i);
    }
}

