        rotate([0, 0, 0])
        translate([x, y, z])
        rotate([acos(z / sphere_radius), atan2(y, x), 0])
        cylinder(r = protrusion_radius, h = sphere_radius + protrusion_height - sphere_radius, $fn = 30);
    }
}

