$fn = 100;

module rounded_triangle(r, h) {
    hull() {
        translate([r * cos(0), r * sin(0), 0]) cylinder(r=10, h=h);
        translate([r * cos(120), r * sin(120), 0]) cylinder(r=10, h=h);
        translate([r * cos(240), r * sin(240), 0]) cylinder(r=10, h=h);
    }
}

difference() {
    union() {
        // Main plate
        rounded_triangle(plate_radius, plate_thickness);

        // Raised beveled edge
        difference() {
            rounded_triangle(plate_radius, plate_thickness + edge_height);
            translate([0, 0, plate_thickness])
            scale([0.85, 0.85, 1])
            rounded_triangle(plate_radius, edge_height + 1);
        }

        // Cylindrical extension
        translate([plate_radius, 0, 0])
        cylinder(r=cylinder_ext_radius, h=cylinder_ext_height);
    }

    // Recessed area
    translate([0, 0, plate_thickness - recess_depth + 0.1])
    scale([0.8, 0.8, 1])
    rounded_triangle(plate_radius, recess_depth);

    // Three circular holes
    for (a = [0, 120, 240]) {
        rotate([0, 0, a])
        translate([plate_radius * 0.5, 0, -1])
        cylinder(r=hole_radius, h=plate_thickness + 2);
    }
}

ring_radius = 40;
tube_radius = 5;
num_segments = 60;
noise_factor = 0.8;
protrusion_count = 12;

$fn = 32;

union() {
    for (i = [0 : num_segments - 1]) {
        angle = i * (360 / num_segments);
        x = (ring_radius + rands(-noise_factor, noise_factor, 1)[0]) * cos(angle);
        y = (ring_radius + rands(-noise_factor, noise_factor, 1)[0]) * sin(angle);
        z = rands(-noise_factor, noise_factor, 1)[0];

        hull() {
            translate([x, y, z])
            sphere(r = tube_radius + rands(-0.5, 0.5, 1)[0]);

            next_angle = (i + 1) * (360 / num_segments);
            nx = (ring_radius + rands(-noise_factor, noise_factor, 1)[0]) * cos(next_angle);
            ny = (ring_radius + rands(-noise_factor, noise_factor, 1)[0]) * sin(next_angle);
            nz = rands(-noise_factor, noise_factor, 1)[0];

            translate([nx, ny, nz])
            sphere(r = tube_radius + rands(-0.5, 0.5, 1)[0]);
        }
    }

    for (j = [0 : protrusion_count - 1]) {
        p_angle = j * (360 / protrusion_count);
        px = (ring_radius + tube_radius) * cos(p_angle);
        py = (ring_radius + tube_radius) * sin(p_angle);

        translate([px, py, 0])
        rotate([0, 0, p_angle])
        rotate([0, 90, 0])
        cylinder(r1 = 2, r2 = 0, h = 4);

        px2 = (ring_radius - tube_radius) * cos(p_angle);
        py2 = (ring_radius - tube_radius) * sin(p_angle);

        translate([px2, py2, 0])
        rotate([0, 0, p_angle])
        rotate([0, -90, 0])
        cylinder(r1 = 2, r2 = 0, h = 4);
    }
}

