module wireframe_cube(size, thickness) {
    s = size;
    t = thickness;

    // Edges
    for (x = [0, 1]) for (y = [0, 1]) 
        translate([x*s, y*s, 0]) rotate([0, 90, 0]) cylinder(h=s, r=t/2, $fn=16);
    for (x = [0, 1]) for (z = [0, 1]) 
        translate([x*s, 0, z*s]) rotate([-90, 0, 0]) cylinder(h=s, r=t/2, $fn=16);
    for (y = [0, 1]) for (z = [0, 1]) 
        translate([0, y*s, z*s]) rotate([0, 0, 0]) cylinder(h=s, r=t/2, $fn=16);

    // Corners
    for (x = [0, 1]) for (y = [0, 1]) for (z = [0, 1])
        translate([x*s, y*s, z*s]) sphere(r=t/2, $fn=16);
}

union() {
    translate([-cube_size/2, -cube_size/2, -cube_size/2]) 
        wireframe_cube(cube_size, wire_thickness);

    rotate([rotation_angle, rotation_angle, 0]) 
        translate([-cube_size/2, -cube_size/2, -cube_size/2]) 
            wireframe_cube(cube_size, wire_thickness);
}

