module wall() {
    for (y = [0 : brick_h + mortar : wall_height]) {
        offset = (y / (brick_h + mortar)) % 2 == 0 ? 0 : (brick_w + mortar) / 2;
        for (x = [-(wall_width/2) : brick_w + mortar : wall_width/2]) {
            translate([x + offset, y - (wall_height/2), 0])
                brick();
        }
    }
}

