color([1, 1, 1]) {
    difference() {
        cylinder(r = radius + thickness, h = height, $fn = 100);
        cylinder(r = radius, h = height, $fn = 100);
        translate([-radius - thickness, -radius - thickness, 0])
            cube([radius + thickness, (radius + thickness) * 2, height]);
        translate([-radius - thickness, -radius - thickness, 0])
            cube([(radius + thickness) * 2, radius + thickness, height]);
    }
}

color([0.6, 0.4, 0.2]) {
    for (a = [0 : 10 : 90]) {
        rotate([0, 0, a])
            translate([radius + thickness, 0, 0])
                cube([grid_thickness, grid_thickness, height]);
    }

    for (z = [0 : grid_spacing : height]) {
        difference() {
            rotate_extrude(angle = 90, $fn = 100)
                translate([radius + thickness, 0, 0])
                    square([grid_thickness, grid_thickness]);
            translate([-radius * 2, -radius * 2, z - grid_thickness/2])
                cube([radius * 4, radius * 4, grid_thickness]);
        }
    }
}

