module rock_base() {
    hull() {
        sphere(r = rock_size * 0.6, $fn = 20);
        translate([rock_size * 0.4, 0, rock_size * 0.2]) sphere(r = rock_size * 0.5, $fn = 20);
        translate([-rock_size * 0.3, rock_size * 0.3, -rock_size * 0.3]) sphere(r = rock_size * 0.4, $fn = 20);
    }
