module shell_formation() {
    difference() {
        sphere(r = 4, $fn = 12);
        translate([0, 0, 1]) sphere(r = 3, $fn = 12);
        translate([0, 0, -2]) cube([10, 10, 2], center = true);
    }
}

difference() {
    union() {
        rock_base();
        for (i = [0 : shell_count]) {
            angle = i * 137.5;
            dist = (i / shell_count) * rock_size * 0.5;
            z_pos = sin(i * 50) * rock_size * 0.4;

            rotate([0, 0, angle])
            translate([dist, 0, z_pos])
            rotate([i * 20, i * 30, 0])
            shell_formation();
        }
    }

    for (i = [0 : 10]) {
        translate([sin(i*40)*rock_size, cos(i*40)*rock_size, 0])
        sphere(r = rock_size * 0.3, $fn = 10);
    }
}

