$fn = 50;

module ring(r, angle_offset) {
    rotate([0, angle_offset, 0])
    rotate_extrude(angle = 360)
    translate([r, 0, 0])
    circle(d = thickness);
}

module lattice_sphere() {
    difference() {
        sphere(r = radius, $fn = 100);
        sphere(r = radius - thickness, $fn = 100);

        union() {
            for (i = [0 : num_rings - 1]) {
                angle = (i / num_rings) * 180;
                rotate([0, 0, (i % 2) * (180 / num_segments)])
                for (j = [0 : num_segments - 1]) {
                    rotate([0, 0, (j / num_segments) * 360])
                    rotate([0, 90, 0])
                    cylinder(r = radius * 0.8, h = thickness * 2, center = true);
                }
            }
        }
    }
}

intersection() {
    lattice_sphere();
