hole_radius = 3;

module bismuth_crystal(offset_x, offset_y, rot_z) {
    translate([offset_x, offset_y, 0])
    rotate([0, 0, rot_z])
    union() {
        difference() {
            union() {
                for (i = [0 : step_count - 1]) {
                    scale_factor = 1 - (i * 0.15);
                    translate([0, 0, i * step_height])
                    cube([base_size * scale_factor, base_size * scale_factor, step_height], center = true);
                }
            }
            cylinder(r = hole_radius, h = step_count * step_height * 2, center = true);
        }

        difference() {
            cylinder(r = cylinder_radius, h = step_count * step_height, center = false);
            translate([0, 0, -1])
            cylinder(r = hole_radius, h = step_count * step_height + 2, center = false);
        }
    }
}

union() {
    bismuth_crystal(-25, 0, 30);
    mirror([1, 0, 0])
    bismuth_crystal(-25, 0, -15);
}

barrel_len = 400;
barrel_rad = 15;
stock_len = 150;
stock_height = 60;
suppressor_len = 120;
suppressor_rad = 20;
ammo_box_size = [60, 40, 80];

union() {
    // Main Receiver
    color("gray")
    translate([0, 0, 0])
    cube([300, 40, 50], center=true);

    // Barrel
    color("darkgray")
    translate([250, 0, 0])
    rotate([0, 90, 0])
    cylinder(h=barrel_len, r=barrel_rad, $fn=50);

    // Suppressor
    color("black")
    translate([450, 0, 0])
    rotate([0, 90, 0])
    cylinder(h=suppressor_len, r=suppressor_rad, $fn=50);

    // Wooden Stock
    color([0.6, 0.3, 0.1])
    translate([-225, 0, 0])
    cube([stock_len, 30, stock_height], center=true);

    // Grip
    color([0.6, 0.3, 0.1])
    translate([-50, 0, -50])
    rotate([20, 0, 0])
    cube([20, 30, 60], center=true);

    // Ammo Box
    color("green")
    translate([50, 50, -20])
    cube(ammo_box_size);

    // Feed Tray
    color("darkgray")
    translate([50, 20, 20])
    cube([40, 30, 10]);
}

base_radius = 60;
base_height = 80;
bottle_radius = 35;
bottle_height = 150;
panel_width = 40;
panel_height = 50;

union() {
    // Blender Base
    difference() {
        cylinder(r = base_radius, h = base_height, $fn = 64);
        translate([0, 0, base_height - 5])
            cylinder(r = bottle_radius + 2, h = 10, $fn = 64);
    }

    // Control Panel
    translate([base_radius - 2, -panel_width / 2, 15])
        cube([5, panel_width, panel_height]);

    // Control Knobs
    translate([base_radius, 0, 40])
        rotate([0, 90, 0])
            cylinder(r = 8, h = 10, $fn = 32);

    // Blender Bottle
    translate([0, 0, base_height - 5])
        union() {
            cylinder(r = bottle_radius, h = bottle_height, $fn = 64);
            // Bottle Cap
            translate([0, 0, bottle_height])
                cylinder(r = bottle_radius + 2, h = 10, $fn = 64);
        }
}

base_width = 100;
base_depth = 60;
base_height = 5;

block_width = 20;
block_depth = 20;
block_height = 15;

cyl_radius = 5;
cyl_length = 40;
support_width = 5;
support_height = 10;

protrusion_size = 5;

union() {
    // Base
    cube([base_width, base_depth, base_height]);

    // Raised rectangular block
    translate([10, 10, base_height])
        cube([block_width, block_depth, block_height]);

    // Horizontal cylinder with supports
    translate([50, 10, base_height]) {
        // Supports
        cube([support_width, support_width, support_height]);
        translate([cyl_length - support_width, 0, 0])
            cube([support_width, support_width, support_height]);

        // Cylinder
        translate([0, support_width/2, support_height + cyl_radius])
            rotate([0, 90, 0])
                cylinder(r = cyl_radius, h = cyl_length);
    }

    // Two small vertical protrusions
    translate([80, 40, base_height])
        cube([protrusion_size, protrusion_size, 15]);

    translate([90, 40, base_height])
        cube([protrusion_size, protrusion_size, 10]);
}
